// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < 7; i++) {
        int ki;
        scanf("%d", &ki);
        printf("%d\n", ki);
        for (int j = 0; j < ki; j++) {
            int startHour, startMinute, endHour, endMinute;
            scanf("%d:%d %d:%d", &startHour, &startMinute, &endHour, &endMinute);
            startHour -= T;
            endHour -= T;
            if (startHour < 0) {
                startHour += 24;
            }
            if (endHour < 0) {
                endHour += 24;
            }
            printf("%02d:%02d %02d:%02d\n", startHour, startMinute, endHour, endMinute);
        }
    }
    return 0;
}

