import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int i = 0; i < 7; i++) {
            int ki = scanner.nextInt();
            System.out.println(ki);
            for (int j = 0; j < ki; j++) {
                String[] startTime = scanner.next().split(":");
                String[] endTime = scanner.next().split(":");
                int startHour = Integer.parseInt(startTime[0]) - T;
                int endHour = Integer.parseInt(endTime[0]) - T;
                if (startHour < 0) {
                    startHour += 24;
                }
                if (endHour < 0) {
                    endHour += 24;
                }
                System.out.printf("%02d:%02d %02d:%02d\n", startHour, Integer.parseInt(startTime[1]), endHour, Integer.parseInt(endTime[1]));
            }
        }
    }
}

